class Solution:
    def levelOrderBottom(self, root):
        levels = []
        def walk(node, depth):
            if node is None:
                return
            if depth == len(levels):
                levels.append([])
            levels[depth].append(node.val)
            walk(node.left, depth + 1)
            walk(node.right, depth + 1)
        walk(root, 0)
        return levels[::-1]

