var levelOrderBottom = function(root) {
    if (!root) return [];
    const res = [];
    let level = [root];
    while (level.length) {
        const vals = [];
        const next = [];
        for (const node of level) {
            vals.push(node.val);
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        res.unshift(vals);
        level = next;
    }
    return res;
};
